// frontend/src/pages/UploadResume.js
import React, { useState } from 'react';
import axios from 'axios';

const UploadResume = () => {
  const [resumeText, setResumeText] = useState('');
  const [uploading, setUploading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');

  const token = localStorage.getItem('token');
  const BACKEND_URL = 'http://localhost:5000';

  // Save to backend database
  const saveToDatabase = async (resumeText) => {
    try {
      const response = await axios.post(
        `${BACKEND_URL}/api/applications`,
        {
          jobTitle: 'Resume Upload',
          companyName: 'My Profile',
          status: 'Saved',
          resumeText: resumeText,
          jobDescription: 'AI analyzed resume for job matching',
          notes: 'Uploaded for AI job recommendations'
        },
        { headers: { 'x-auth-token': token } }
      );
      console.log('Saved to database:', response.data);
      return true;
    } catch (error) {
      console.error('Database save error:', error.response?.data || error.message);
      return false;
    }
  };

  const handleUpload = async () => {
    if (!resumeText) {
      setMessage('Please paste your resume text');
      setMessageType('error');
      return;
    }

    setUploading(true);
    
    try {
      // Save to localStorage (for AI quick access)
      localStorage.setItem('userResume', resumeText);
      
      // Save to backend database (for web tech project)
      const dbSaved = await saveToDatabase(resumeText);
      
      if (dbSaved) {
        setMessage('✅ Resume saved to database and AI system!');
        setMessageType('success');
      } else {
        setMessage('⚠️ Saved locally but database save failed. Check backend.');
        setMessageType('warning');
      }
      
      // Clear message after 3 seconds
      setTimeout(() => setMessage(''), 3000);
      
    } catch (error) {
      console.error('Save error:', error);
      setMessage('❌ Error saving resume');
      setMessageType('error');
    }
    setUploading(false);
  };

  const clearResume = () => {
    localStorage.removeItem('userResume');
    setResumeText('');
    setMessage('🗑️ Resume cleared from local storage');
    setMessageType('success');
    setTimeout(() => setMessage(''), 2000);
  };

  return (
    <div style={{ padding: '20px', maxWidth: '800px', margin: '0 auto' }}>
      <h1>📄 Upload Your Resume</h1>
      
      <div style={{
        padding: '10px',
        borderRadius: '5px',
        marginBottom: '20px',
        background: '#e8f4f8',
        color: '#0c5460'
      }}>
        ℹ️ Your resume will be saved to:
        <ul style={{ marginTop: '5px', marginBottom: '0' }}>
          <li>✅ Local storage (for AI quick access)</li>
          <li>✅ Database (for your job applications)</li>
        </ul>
      </div>
      
      <div style={{ marginBottom: '20px' }}>
        <label style={{ display: 'block', marginBottom: '10px', fontWeight: 'bold' }}>
          Paste your resume text here:
        </label>
        <textarea
          rows={15}
          value={resumeText}
          onChange={(e) => setResumeText(e.target.value)}
          placeholder="Paste your resume content here..."
          style={{
            width: '100%',
            padding: '10px',
            border: '1px solid #ddd',
            borderRadius: '5px',
            fontFamily: 'monospace',
            fontSize: '14px'
          }}
        />
      </div>

      <div style={{ display: 'flex', gap: '10px' }}>
        <button
          onClick={handleUpload}
          disabled={uploading}
          style={{
            padding: '10px 20px',
            background: '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: uploading ? 'not-allowed' : 'pointer',
            opacity: uploading ? 0.6 : 1
          }}
        >
          {uploading ? 'Saving...' : '📤 Save Resume'}
        </button>

        <button
          onClick={clearResume}
          style={{
            padding: '10px 20px',
            background: '#dc3545',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            cursor: 'pointer'
          }}
        >
          🗑️ Clear Resume
        </button>
      </div>

      {message && (
        <div style={{
          marginTop: '20px',
          padding: '10px',
          borderRadius: '5px',
          background: messageType === 'success' ? '#d4edda' : (messageType === 'warning' ? '#fff3cd' : '#f8d7da'),
          color: messageType === 'success' ? '#155724' : (messageType === 'warning' ? '#856404' : '#721c24'),
          border: `1px solid ${messageType === 'success' ? '#c3e6cb' : (messageType === 'warning' ? '#ffeeba' : '#f5c6cb')}`
        }}>
          {message}
        </div>
      )}

      {/* Sample Resume Section */}
      <div style={{ marginTop: '30px', padding: '15px', background: '#f5f5f5', borderRadius: '10px' }}>
        <h3>📝 Sample Resume (Click to use)</h3>
        <pre style={{ whiteSpace: 'pre-wrap', fontSize: '12px', background: 'white', padding: '10px', borderRadius: '5px' }}>
